def shell_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
    """Return a list of completions for the incomplete value. A manual
    ``shell_complete`` callback always takes precedence. Otherwise, if
    :attr:`auto_complete` is enabled, completions are generated by
    :meth:`_smart_complete`. Otherwise, falls back to the behavior of
    :meth:`Parameter.shell_complete`.

    :param ctx: Invocation context for this command.
    :param incomplete: Value being completed. May be empty.

    .. versionadded:: 8.3
    """
    if self._custom_shell_complete is None and self.auto_complete:
        results = self._smart_complete(ctx, incomplete)

        if results and isinstance(results[0], str):
            from click.shell_completion import CompletionItem

            results = [CompletionItem(c) for c in results]

        return t.cast("list[CompletionItem]", results)

    return super().shell_complete(ctx, incomplete)

def _smart_complete(
    self, ctx: Context, incomplete: str
) -> list[CompletionItem] | list[str]:
    """Determine the appropriate completion strategy for this option
    based on its name and type, and return completions for
    ``incomplete``. Used when :attr:`auto_complete` is ``True``.

    The option's declared names (e.g. ``--user``) and its destination
    name (e.g. ``user``) are matched against
    :data:`~click.types.AUTO_COMPLETE_REGISTRY` to find a completion
    function. If no pattern matches, falls back to the option's
    :attr:`type` completion.

    :param ctx: Invocation context for this command.
    :param incomplete: Value being completed. May be empty.

    .. versionadded:: 8.3
    """
    from .types import AUTO_COMPLETE_REGISTRY

    candidates = [self.name or ""]
    candidates.extend(_split_opt(opt)[1] for opt in self.opts)
    candidates = [name.lower().replace("-", "_") for name in candidates]

    for pattern, complete_func in AUTO_COMPLETE_REGISTRY.items():
        if any(pattern in name for name in candidates):
            return complete_func(ctx, self, incomplete)

    return self.type.shell_complete(ctx, self, incomplete)

